var TIT=null;

function ReplaceResource(recID) {
	var recValue=Ctrl("main").getResource(recID);
	recValue=Replace(recValue,"#RESOURCE-LIST#"  ,CFG.GetAttr("RESOURCE-LIST"  ));
	recValue=Replace(recValue,"#RESOURCE-ID#"    ,CFG.GetAttr("RESOURCE-ID"    ));
	recValue=Replace(recValue,"#RESOURCE-PARENT#",CFG.GetAttr("RESOURCE-PARENT"));
	recValue=Replace(recValue,"#RESOURCE-OBJECT#",CFG.GetAttr("RESOURCE-OBJECT"));

	Ctrl("main").setResource(recValue, recID);
}

function RefreshReport() {
	//Actualiza el reporte del formulario
	var strURL;

	strURL = "../../../ReportViewer.aspx?file=NucleusWF.Base.Definicion.WFPLA_Main.rpt" +
					"&ut=" + GetProxy().UserToken() +
					"&id=" + Ctrl("PARENT").GetXValue() +
					"&mode=DES" +
					"&now=" + datetime2str(new Date());

	Ctrl("REPORT_ORG").SetURL(strURL);
}

///////////////////////////////////////////////////////////////////////////////          
//CONTEXTS MENUES

function OpenMenu(pstrParam, pstrMenu, pEvent) {
	var objCtrl;

	objCtrl = Ctrl("hidMenus");

	CreateMenu(objCtrl, pstrMenu);

	objCtrl.SetXValue(pstrParam);
	objCtrl.OnContextMenu(pEvent);

}

function CreateMenu(pobjCtrl, pstrMenu) {
	var xmlMenu = new NomadXML(pstrMenu);
	var intSep = 0;

	pobjCtrl.ClearContextMenu();

	//Recorre el xml y crea los items del menu
	var xmlItem;
	for (xmlItem = xmlMenu.FirstChild(); xmlItem != null; xmlItem = xmlItem.Next()) {

		if (xmlItem.Name == "item") {

			pobjCtrl.AddContextMenu(xmlItem.GetAttr("name"), xmlItem.GetAttr("label"), xmlItem.GetAttr("img"));
			pobjCtrl.SetClientEvent("CONTEX_MENU_" + xmlItem.GetAttr("name"), xmlItem.GetAttr("event"));

		} else {
			pobjCtrl.AddContextMenu("S" + intSep.toString(), "-", "");
			intSep++;
		}
	}

}

function FlowResult() {
	this.processResult = function(xml) {
		RefreshReport();
	}
}

///////////////////////////////////////////////////////////////////////////////          
//EVENTOS
function OnLoad() {                
	if(Ctrl("main").GetMode() != "SCRIPT")
	{
		//Cargo la Configuracion
		CFG =new NomadXML(Ctrl("main").getResource("QRY_CFG"));

		//Modifico los Recursos
		ReplaceResource("QRY_IDS_PARENT");

		//Actualizo la Pantalla
		RefreshReport();
	}
	if(Ctrl("main").GetMode() == "SCRIPT")
	{                          
		var script = Ctrl("hid_script_1").GetXValue();
		script 		+= Ctrl("hid_script_2").GetXValue();
		script 		+= Ctrl("hid_script_3").GetXValue(); 
		script 		+= Ctrl("hid_script_4").GetXValue();  
		Ctrl("o_script").SetXValue(script);
	}
}


///////////////////////////////////////////////////////////////////////////////          
//Acciones de los Context menues

//Administrador de Grupos
function GroupsManager(pObj) {
	var arrMenuItem;
	var FlowAction = pObj.ClickContextMenuId;
	var xmlValue = new NomadXML(pObj.GetXValue());

	arrMenuItem = FlowAction.split("_");
	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.FORM_GROUP.flow", "FORM_GROUP_" + arrMenuItem[1], '<PARAMS ID="'+ xmlValue.GetAttr("id") +'" PARENT="'+ xmlValue.GetAttr("parent") +'" MODE="'+ arrMenuItem[0]  +'" />', new FlowResult(), "L");
}


//Administrador de Campos (Fields)

//GroupField --------------------
function FieldsManager(pObj) {
	var strXMLParam;
	var FlowAction = pObj.ClickContextMenuId;
	var xmlValue = new NomadXML(pObj.GetXValue());

	if (FlowAction == "EDIT")
		strXMLParam = '<PARAMS ID="'+ xmlValue.GetAttr("id") +'" PARENT="'+ xmlValue.GetAttr("parent") +'" />';
	else
		strXMLParam = '<PARAMS PARENT="'+ xmlValue.GetAttr("id") +'" />';

	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.FIELD.flow", "FORM_FIELD_" + FlowAction, strXMLParam, new FlowResult(), "L");
}

function GroupField_Del(pObj) {
	if (confirm("¿Está seguro que desea eliminar el control?")) {
		var xmlValue = new NomadXML(pObj.GetXValue());
		openNewFlowWait("NucleusWF.Base.Definicion.Workflows.FORM.flow", "FieldDelete", '<PARAM oi_field="'+ xmlValue.GetAttr("id") +'" />', new FlowResult(), "L");
	}
}

function GroupField_Up(pObj) {
	var xmlValue = new NomadXML(pObj.GetXValue());
	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.FORM.flow", "FieldUpDown", '<PARAM oi_field="'+ xmlValue.GetAttr("id") +'" direction="UL"/>', new FlowResult(), "L");
}

function GroupField_Down(pObj) {
	var xmlValue = new NomadXML(pObj.GetXValue());
	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.FORM.flow", "FieldUpDown", '<PARAM oi_field="'+ xmlValue.GetAttr("id") +'" direction="DR"/>', new FlowResult(), "L");
}

