function Variables()
{                                                                                            
	appendFormInMain("NucleusWF.Base.Definicion.Workflows.VAR.flow", "DESIGN", '<DATA PARENT="'+Ctrl("WF").GetXValue()+'" />');
}

function save()
{
	var script  = Ctrl("o_script").GetXValue();
	if(script.length > 15600) 
	{
		alert("El texto supera los 15000. Por favor revise el contenido.");
		return false;
	}             
	else
	{
		var script1 = script.substring(0,3900);
		var script2 = script.substring(3900,7800);
		var script3 = script.substring(7800,11700);
		var script4 = script.substring(11700,15600);
		Ctrl("hid_script_1").SetXValue(script1);
		Ctrl("hid_script_2").SetXValue(script2);
		Ctrl("hid_script_3").SetXValue(script3);
		Ctrl("hid_script_4").SetXValue(script4);
		Ctrl("main").DoEvent("SAVE");
	}
}
